        dp[0][0] = 0
        for i in range(1, len(nums)+1):
            dp[i][0] = max(dp[i-1][0], dp[i-1][1] + nums[i-1])
        for j in range(1, K+1):
            for i in range(j, len(nums)+1):
                dp[i][j] = max(dp[i-1][j-1] + nums[i-1], dp[i-1][j])
        return dp[len(nums)][K]


