#include <stdio.h>
#include <algorithm>
#include <vector>

using namespace std;

class Solution {
public:
    int maxSum(vector<int>& nums, int K, int S) {
        int n = nums.size();
        vector<vector<int>> dp(n+1, vector<int>(K+1, 0));
        dp[0][0] = 0;
        for (int i=1; i<=n; i++)
            dp[i][0] = max(dp[i-1][0], dp[i-1][1] + nums[i-1]);
        for (int j=1; j<=K; j++)
            for (int i=j; i<=n; i++)
                dp[i][j] = max(dp[i-1][j-1] + nums[i-1], dp[i-1][j]);
        return dp[n][K];
    }
};

